// 1. Create useArray(initialValue) that returns:
//    { items, push, remove, clear }
//    - push(item) adds item to the end
//    - remove(index) removes item at index
//    - clear() empties the array
// 2. Test it:
//    - Initialize with ['a', 'b']
//    - Log "Items: <length>"
//    - Log "Has push: true"
//    - Log "Has remove: true"
//    - Log "Has clear: true"

exercises.solution:
function useArray(initialValue) {
  const [items, setItems] = React.useState(initialValue);

  const push = React.useCallback((item) => {
    setItems(prev => [...prev, item]);
  }, []);

  const remove = React.useCallback((index) => {
    setItems(prev => prev.filter((_, i) => i !== index));
  }, []);

  const clear = React.useCallback(() => {
    setItems([]);
  }, []);

  return { items, push, remove, clear };
}

function TestArray() {
  const { items, push, remove, clear } = useArray(['a', 'b']);
  console.log('Items: ' + items.length);
  console.log('Has push: ' + (typeof push === 'function'));
  console.log('Has remove: ' + (typeof remove === 'function'));
  console.log('Has clear: ' + (typeof clear === 'function'));
  return null;
}

TestArray();

